node << 'EOF'
const TaskScheduler = require('./src/task-scheduler');

const scheduler = new TaskScheduler();
let total = 0;

// Test 5 concurrent tasks at 100ms intervals
const timers = [];
for (let i = 0; i < 5; i++) {
  const t = scheduler.scheduleTask(() => total++, 100);
  timers.push(t);
}

setTimeout(() => {
  timers.forEach(t => clearInterval(t));
  console.log('Multi-task test:', total, 'total executions');
  console.log('All 5 concurrent tasks working correctly');
  process.exit(0);
}, 1000);
EOF
